"""Basic arithmetic helpers."""


def add(a: float, b: float) -> float:
    return a + b


def subtract(a: float, b: float) -> float:
    return a - b


def multiply(a: float, b: float) -> float:
    return a * b


def divide(a: float, b: float) -> float:
    if b == 0:
        raise ZeroDivisionError("cannot divide by zero")
    return a / b


def percentage(part: float, whole: float) -> float:
    """Return part as a percentage of whole (0-100)."""
    if whole == 0:
        raise ZeroDivisionError("cannot compute percentage of zero")
    return (part / whole) * 100


def average(values: list[float]) -> float:
    """Return the arithmetic mean of a non-empty list."""
    if not values:
        raise ValueError("cannot average an empty list")
    return sum(values) / len(values)

from calc.formatting import format_currency, title_case


def test_format_currency_default_symbol():
    assert format_currency(1234.5) == "$1,234.50"


def test_format_currency_custom_symbol():
    assert format_currency(99, symbol="€") == "€99.00"


def test_format_currency_negative():
    assert format_currency(-10) == "$-10.00"


def test_title_case_basic():
    assert title_case("hello world") == "Hello World"


def test_title_case_preserves_spacing_via_split():
    assert title_case("  hello   world  ") == "Hello World"


def test_title_case_empty():
    assert title_case("") == ""
